function partitionLabels(s) {
    const lastPos = {};
    for (let i = 0; i < s.length; i++) {
        lastPos[s[i]] = i;
    }

    const partitions = [];
    let start = 0, end = 0;
    for (let i = 0; i < s.length; i++) {
        end = Math.max(end, lastPos[s[i]]);
        if (i === end) {
            partitions.push(end - start + 1);
            start = i + 1;
        }
    }
    return partitions;
}
